command:
const speaker = ChatMessage.getSpeaker();
const actor = canvas.tokens.controlled[0]?.actor ?? game.actors.get(speaker.actor);
if (!actor || actor.type !== "agent") return ui.notifications.warn(game.i18n.localize("op.macroSelectAgent"));

const pe = actor.system.PE;
const pd = actor.system.PD;
const peGain = Math.min(pe.perRound ?? 1, pe.max - pe.value);
const pdGain = Math.min(pd.perRound ?? 1, pd.max - pd.value);

await actor.update({
	"system.PE.value": pe.value + peGain,
	"system.PD.value": pd.value + pdGain,
});

ChatMessage.create({
	speaker: ChatMessage.getSpeaker({ actor }),
	content: game.i18n.format("op.macroShortRestRecovered", { actor: actor.name, pe: peGain, pd: pdGain }),
});
